1	const PROCESSING_FEE = 5;
2	const BLOCK_SIZE = 3;
3	const COMPONENT_BLOCK_PREMIUM = 60;
4	
5	const BASE_PREMIUMS: Record<string, number> = {
6	  sword: 100,
7	  amulet: 60,
8	  staff: 80,
9	  potion: 40,
10	  rune: 25,
11	  moonstone: 25,
12	};
13	
14	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
15	
16	const isComponent = (item: any): boolean => COMPONENT_TYPES.has(item.type);
17	
18	const basePremium = (item: any): number =>
19	  BASE_PREMIUMS[item.type] ?? 0;
20	
21	const groupByType = (items: any[]): Record<string, number> =>
22	  items.reduce(
23	    (counts: Record<string, number>, item: any) => ({
24	      ...counts,
25	      [item.type]: (counts[item.type] ?? 0) + 1,
26	    }),
27	    {},
28	  );
29	
30	const componentGroupPremium = (type: string, count: number): number =>
31	  count === BLOCK_SIZE ? COMPONENT_BLOCK_PREMIUM : count * (BASE_PREMIUMS[type] ?? 0);
32	
33	const quotePremium = (items: any[]): number => {
34	  const components = items.filter(isComponent);
35	  const nonComponents = items.filter((item: any) => !isComponent(item));
36	  const itemPremium = nonComponents.reduce((sum: number, item: any) => {
37	    const base = basePremium(item);
38	    const curseSurcharge = item.cursed ? base * 0.5 : 0;
39	    const enchantmentSurcharge = item.enchantment >= 5 ? base * 0.3 : 0;
40	    return sum + base + curseSurcharge + enchantmentSurcharge;
41	  }, 0);
42	  const componentTotal = Object.entries(groupByType(components)).reduce(
43	    (sum: number, [type, count]: [string, number]) => sum + componentGroupPremium(type, count),
44	    0,
45	  );
46	  return itemPremium + componentTotal + PROCESSING_FEE;
47	};
48	
49	export const processScenario = (scenario: any): any => ({
50	  results: scenario.steps.map((step: any) => ({
51	    premium: quotePremium(step.items),
52	  })),
53	});
